protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents remain queryable and
        // direct SQL queries referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id.
        // Preserve the old "Product|123" id format so existing documents stay accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // HasIndex removed — EF Core 9 Cosmos provider throws on HasIndex.
    // Manage indexing via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

